#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
const int MAXN=1e2+5;
int a[MAXN],lax[MAXN],rax[MAXN],n,r,ans=0;
int main(void){
    n=read(),r=read();
    for(int i=1;i<=n;++i)
    {
        a[i]=r%10;
        r=(r*6807+2831)%201701;
    }
    lax[1]=a[1];
    for(int i=2;i<=n;++i)
    {
        lax[i]=max(lax[i-1],a[i]);
    }
    rax[n]=a[n];
    for(int i=n-1;i>=1;--i)
    {
        rax[i]=max(rax[i+1],a[i]);
    }
    for(int i=1;i<=n;++i)
    {
        ans+=max(0,min(lax[i],rax[i])-a[i]);
    }
    write(ans);
	return false;
}
